export const GLOBAL_IGNORE_PATTERNS: string[] = [
	".git/index",
	".git/index.lock",
	".git/HEAD.lock",
	".git/refs/**/*.lock",
	".git/objects/tmp_*",
	".git/MERGE_*",
	".git/FETCH_HEAD",
	".git/ORIG_HEAD",
	"node_modules",
	".next",
	".nuxt",
	".turbo",
	".cache",
	"dist",
	"build",
	"out",
	"target",
	"__pycache__",
	".venv",
	".env.local",
	".DS_Store",
	"Thumbs.db",
	"*.swp",
	"*.swo",
	"*~",
	"*.log",
	".pnpm-store",
	".yarn",
];

export function buildStignore(bucketIgnore: string[], globalIgnore: string[] = []): string {
	const lines = [
		"// Generated by ccsync — do not edit manually",
		"",
		"// Global protections",
		...GLOBAL_IGNORE_PATTERNS,
		...globalIgnore,
		"",
		"// Bucket-specific",
		...bucketIgnore,
		"",
	];
	return lines.join("\n");
}
